import { Compass } from './components/ui/Compass';
import { CONTENT } from './constants';
import { Language, Theme } from './types';
import { ArrowRight, Mic, ShoppingBag, Wind } from 'lucide-react';

// Metallic Gradient Definitions
const GRADIENT_GOLD = "bg-gradient-to-br from-[#bf953f] via-[#fcf6ba] to-[#b38728]";
const GRADIENT_GOLD_TEXT = "bg-gradient-to-b from-[#bf953f] via-[#fcf6ba] to-[#b38728] bg-clip-text text-transparent";
const GRADIENT_SILVER = "bg-gradient-to-br from-[#8a98a6] via-[#e8eaeb] to-[#748290]";
const GRADIENT_SILVER_TEXT = "bg-gradient-to-b from-[#8a98a6] via-[#e8eaeb] to-[#748290] bg-clip-text text-transparent";
const GRADIENT_COPPER = "bg-gradient-to-br from-[#E6A374] via-[#9A6B49] to-[#5D3A29]";

const BG_MUSIC_URL = "https://storage.googleapis.com/inspirata/Base%20site/Whispers%20of%20Rivendell.mp3";

const App: React.FC = () => {
  const [lang, setLang] = useState<Language>('fr');
  const [theme, setTheme] = useState<Theme>('light');
  const [scale, setScale] = useState(1);
  const [isMusicPlaying, setIsMusicPlaying] = useState(false);
  const audioRef = useRef<HTMLAudioElement | null>(null);

  const t = CONTENT[lang];

  useEffect(() => {
    if (theme === 'dark') {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }
  }, [theme]);

  // Background Music Logic
  useEffect(() => {
    const audio = new Audio(BG_MUSIC_URL);
    audio.loop = true;
    audio.volume = 0.4;
    audioRef.current = audio;

    const startAudioOnInteraction = () => {
      if (audioRef.current && !isMusicPlaying) {
        audioRef.current.play().then(() => {
          setIsMusicPlaying(true);
        }).catch(err => console.debug("Audio play blocked", err));
      }
      window.removeEventListener('click', startAudioOnInteraction);
      window.removeEventListener('touchstart', startAudioOnInteraction);
    };

    window.addEventListener('click', startAudioOnInteraction);
    window.addEventListener('touchstart', startAudioOnInteraction);

    return () => {
      window.removeEventListener('click', startAudioOnInteraction);
      window.removeEventListener('touchstart', startAudioOnInteraction);
      audio.pause();
    };
  }, []);

  const toggleMusic = () => {
    if (!audioRef.current) return;
    if (isMusicPlaying) {
      audioRef.current.pause();
    } else {
      audioRef.current.play();
    }
    setIsMusicPlaying(!isMusicPlaying);
  };

  const baseStyle = { fontSize: `${scale}rem` };

  return (
    <div className="min-h-screen relative font-sans selection:bg-copper-bruni selection:text-white bg-paper-light dark:bg-ink-forest transition-colors duration-700 flex flex-col w-full overflow-x-hidden" style={baseStyle}>
      {/* Global Grain Overlay */}
      <div className="fixed inset-0 pointer-events-none opacity-[0.03] dark:opacity-[0.05] bg-noise z-50 mix-blend-overlay"></div>

      {/* Ambient Background */}
      <div className="fixed top-0 left-0 w-full h-full overflow-hidden -z-10 pointer-events-none">
        <div className="absolute top-[-20%] left-[-10%] w-[60%] h-[60%] bg-copper-light/20 dark:bg-copper-bruni/10 rounded-full blur-[120px] animate-breathe"></div>
        <div className="absolute bottom-[-10%] right-[-10%] w-[50%] h-[50%] bg-sage/20 dark:bg-ink-forest/40 rounded-full blur-[100px] animate-breathe" style={{ animationDelay: '2s' }}></div>
      </div>

      {/* Header */}
      <header className="fixed top-0 left-0 right-0 z-50 p-6 flex justify-between items-center pointer-events-none">
         <div className="pointer-events-auto font-serif font-semibold tracking-wider text-ink-sureau dark:text-paper text-xl flex items-center">
            Krystine St-Laurent
         </div>
         <div className="pointer-events-auto bg-white/50 dark:bg-black/40 backdrop-blur-md rounded-full px-4 py-2 border border-white/20 shadow-sm">
            <Controls 
              lang={lang} setLang={setLang}
              theme={theme} setTheme={setTheme}
              scale={scale} setScale={setScale}
              isMusicPlaying={isMusicPlaying}
              toggleMusic={toggleMusic}
            />
         </div>
      </header>

      {/* 1. HERO SECTION - Expérience Origine Focus */}
      <section className="relative min-h-[90vh] flex items-center justify-center pt-24 pb-20 px-4 overflow-hidden">
        <SacredGeometry className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-[150%] h-[150%] opacity-5 animate-[spin_120s_linear_infinite] pointer-events-none" />

        <div className="max-w-7xl mx-auto w-full grid grid-cols-1 lg:grid-cols-2 gap-12 items-center relative z-10">
          <div className="order-2 lg:order-1 space-y-8 text-center lg:text-left">
            <div className="inline-flex items-center gap-2 px-4 py-2 rounded-full border border-copper-bruni/30 text-copper-bruni text-xs uppercase tracking-[0.3em] font-semibold bg-copper-bruni/5 backdrop-blur-sm">
              Programme Signature
            </div>
            <h1 className="font-serif text-6xl md:text-8xl text-ink-sureau dark:text-paper leading-[1.1]">
              Expérience <br/><span className="italic text-copper-bruni">Origine</span>
            </h1>
            <p className="text-xl md:text-2xl text-ink-sureau/70 dark:text-paper/70 font-light max-w-xl leading-relaxed mx-auto lg:mx-0">
              {t.hero.subtitle}
            </p>
            <div className="flex flex-col sm:flex-row items-center gap-6 pt-4 justify-center lg:justify-start">
              <a 
                href="https://www.krystinestlaurent.ca/origine"
                target="_blank"
                rel="noopener noreferrer"
                className={`group relative px-12 py-6 rounded-full ${GRADIENT_COPPER} text-white font-bold tracking-[0.2em] uppercase text-base shadow-[0_20px_40px_rgba(154,107,73,0.3)] hover:shadow-[0_25px_50px_rgba(154,107,73,0.4)] hover:scale-105 transition-all duration-500 flex items-center gap-3`}
              >
                {lang === 'fr' ? "M'inscrire sur la liste d'attente" : "Join the waitlist"}
                <ArrowRight size={20} className="group-hover:translate-x-1 transition-transform" />
              </a>
            </div>
          </div>

          <div className="order-1 lg:order-2 flex justify-center items-center relative">
            <div className="absolute inset-0 bg-copper-glow/10 blur-[120px] rounded-full scale-75 animate-pulse"></div>
            <Compass />
          </div>
        </div>
      </section>

      {/* 2. SECONDARY SECTION - The 3 Other Links */}
      <section className="py-24 px-4 bg-white/30 dark:bg-black/10 backdrop-blur-sm border-y border-copper-bruni/10">
        <div className="max-w-7xl mx-auto">
          <div className="grid grid-cols-1 md:grid-cols-3 gap-8">

             {/* Vata Experience */}
             <a href="https://www.krystinestlaurent.ca/vata" target="_blank" rel="noopener noreferrer" className="group relative h-full">
                <div className="bg-[#64694B] rounded-[2.5rem] p-10 h-full border border-[#bf953f]/20 hover:border-[#bf953f] shadow-xl transition-all duration-500 hover:-translate-y-2 flex flex-col justify-between overflow-hidden relative">
                   <div className="absolute -right-8 -bottom-8 w-32 h-32 bg-white/5 rounded-full blur-2xl group-hover:bg-white/10 transition-colors"></div>
                   <div>
                     <div className={`w-14 h-14 rounded-full ${GRADIENT_GOLD} flex items-center justify-center mb-8 shadow-lg shadow-black/20 group-hover:scale-110 transition-transform`}>
                        <Wind size={28} className="text-[#64694B]" />
                     </div>
                     <h3 className="font-serif text-2xl text-[#F2EFE9] mb-4 leading-tight">Expérience Ayurveda :<br/>Saison Vata</h3>
                   </div>
                   <div className="flex items-center gap-2 text-xs font-bold uppercase tracking-widest opacity-80 group-hover:opacity-100 transition-opacity mt-4">
                      <span className={GRADIENT_GOLD_TEXT}>{lang === 'fr' ? "Explorer" : "Explore"}</span>
                      <ArrowRight size={14} className="text-[#bf953f] group-hover:translate-x-1 transition-transform" />
                   </div>
                </div>
             </a>

             {/* Podcast */}
             <a href="https://www.krystinestlaurent.ca/podcast" target="_blank" rel="noopener noreferrer" className="group relative h-full">
                <div className="bg-[#353A29] rounded-[2.5rem] p-10 h-full border border-[#bf953f]/20 hover:border-[#bf953f] shadow-xl transition-all duration-500 hover:-translate-y-2 flex flex-col justify-between overflow-hidden relative">
                   <div className="absolute -right-8 -bottom-8 w-32 h-32 bg-white/5 rounded-full blur-2xl group-hover:bg-white/10 transition-colors"></div>
                   <div>
                     <div className={`w-14 h-14 rounded-full ${GRADIENT_GOLD} flex items-center justify-center mb-8 shadow-lg shadow-black/20 group-hover:scale-110 transition-transform`}>
